export interface DewarpMessage {
  type: "dewarp" | "ready" | "result" | "error" | "log";
  id?: string;
  imageData?: string;
  config?: Partial<PhotoAdjustmentConfig["geometry"]>;
  result?: string;
  error?: string;
  message?: string;
}

