288→export default function ManageBooksScreen(): JSX.Element {
289→  const { t } = useTranslation();
290→  const theme = useTheme();
291→  const colors = getColors(theme);
292→  const insets = useSafeAreaInsets();
293→  const isDark = theme === "dark";
294→  const textColor = isDark ? "#FFFFFF" : "#000000";
295→  const { sources, createSource, renameSource, deleteSource } = useSources();
296→  const { recipes, deleteRecipes } = useRecipes();
297→  const isDeletingRef = useRef(false);
298→
299→  const [isAddingBook, setIsAddingBook] = useState(false);
300→  const [newBookName, setNewBookName] = useState("");
301→  const [editingSourceId, setEditingSourceId] = useState<SourceId | null>(null);
302→  const [editText, setEditText] = useState("");
303→
304→  const recipeCounts = useMemo(() => {
305→    const counts = new Map<SourceId, number>();
306→    for (const recipe of recipes) {
307→      const src = recipe.metadata.source;
308→      if (src && !isUrl(src)) {
309→        counts.set(src, (counts.get(src) ?? 0) + 1);
310→      }
311→    }
312→    return counts;
313→  }, [recipes]);
314→
315→  const handleStartAdd = useCallback(() => {
316→    setIsAddingBook(true);
317→    setNewBookName("");
318→  }, []);
319→
320→  const handleCancelAdd = useCallback(() => {
321→    setIsAddingBook(false);
322→    setNewBookName("");
323→  }, []);
324→
325→  const handleConfirmAdd = useCallback(async () => {
326→    const trimmed = newBookName.trim();
327→    if (!trimmed) return;
328→    try {
329→      await createSource(trimmed);
330→      setIsAddingBook(false);
331→      setNewBookName("");
332→    } catch (error) {
333→      const message = error instanceof Error ? error.message : "";
334→      if (!message.includes("already exists") && !message.includes("cannot be empty") && !message.includes("too long")) {
335→        console.warn("Unexpected error adding book:", error);
336→      }
337→    }
338→  }, [newBookName, createSource]);
339→
340→  const handleDeleteBook = useCallback(
