 8→export function filterRecipes(
 9→  recipes: Array<Recipe>,
10→  searchTerm: string,
11→  tagLookup: Map<TagId, Tag> = new Map()
12→): Array<Recipe> {
13→  const normalizedSearchTerm = searchTerm.trim().replace(/^#/, "");
14→
15→  if (!normalizedSearchTerm) {
16→    return recipes;
17→  }
18→
19→  const fuzzySearch = createFuzzySearch(recipes, {
20→    getText: (recipe) => [
21→      recipe.metadata.title || "",
22→      ...resolveNormalizedTagTexts(recipe.metadata.tagIds, tagLookup),
23→    ],
24→  });
25→
26→  return fuzzySearch(normalizedSearchTerm).map((result) => result.item);
27→}
