29→export function filterRecipesWithQuery(
30→  recipes: Array<Recipe>,
31→  query: SearchQuery,
32→  tagLookup: Map<TagId, Tag>
33→): Array<Recipe> {
34→  const selectedTagIds = query.selectedTags.map((tag) => tag.id);
35→  const andFilteredRecipes = recipes.filter((recipe) => {
36→    return selectedTagIds.every((selectedTagId) =>
37→      recipe.metadata.tagIds.includes(selectedTagId)
38→    );
39→  });
40→
41→  const normalizedFreeText = query.freeText.trim().replace(/^#/, "");
42→  if (!normalizedFreeText) {
43→    return andFilteredRecipes;
44→  }
45→
46→  const fuzzySearch = createFuzzySearch(andFilteredRecipes, {
47→    getText: (recipe) => [
48→      recipe.metadata.title || "",
49→      ...resolveNormalizedTagTexts(recipe.metadata.tagIds, tagLookup),
50→    ],
51→  });
52→
53→  return fuzzySearch(normalizedFreeText).map((result) => result.item);
54→}
