 40→function useActionButtonScale(
 41→  translateX: SharedValue<number>,
 42→  sign: 1 | -1
 43→): { transform: Array<{ scale: number }>; opacity: number } {
 44→  return useAnimatedStyle(() => {
 45→    const w = Math.max(sign * translateX.value - BUTTON_GAP, 0);
 46→    if (w <= SCALE_MIN_WIDTH) {
 47→      return { transform: [{ scale: 0 }], opacity: 0 };
 48→    }
 49→    if (w < BUTTON_SCALE_THRESHOLD) {
 50→      const s =
 51→        (w - SCALE_MIN_WIDTH) / (BUTTON_SCALE_THRESHOLD - SCALE_MIN_WIDTH);
 52→      return { transform: [{ scale: s }], opacity: s };
 53→    }
 54→    return { transform: [{ scale: 1 }], opacity: 1 };
 55→  });
 56→}
 57→
 58→const SWIPE_THRESHOLD = 60;
 59→const ACTION_BUTTON_WIDTH = 80;
 60→const BUTTON_GAP = 12;
 61→const BUTTON_CONTENT_WIDTH = ACTION_BUTTON_WIDTH - BUTTON_GAP;
 62→const BUTTON_SCALE_THRESHOLD = BUTTON_CONTENT_WIDTH;
 63→const SCALE_MIN_WIDTH = 10;
 64→
 65→function SwipeableBookRow({
 66→  source,
 67→  recipeCount,
 68→  editingSourceId,
 69→  onDelete,
 70→  onStartEdit,
 71→  onConfirmEdit,
 72→  onCancelEdit,
 73→  editText,
 74→  onEditTextChange,
 75→}: {
 76→  source: Source;
 77→  recipeCount: number;
 78→  editingSourceId: SourceId | null;
 79→  onDelete: (sourceId: SourceId) => void;
 80→  onStartEdit: (sourceId: SourceId) => void;
 81→  onConfirmEdit: () => void;
 82→  onCancelEdit: () => void;
 83→  editText: string;
 84→  onEditTextChange: (text: string) => void;
 85→}): JSX.Element {
 86→  const { t } = useTranslation();
 87→  const theme = useTheme();
 88→  const colors = getColors(theme);
 89→  const isDark = theme === "dark";
 90→  const textColor = isDark ? "#FFFFFF" : "#000000";
 91→  const translateX = useSharedValue(0);
 92→  const startX = useSharedValue(0);
 93→  const isEditing = editingSourceId === source.id;
 94→  const isEditingShared = useSharedValue(isEditing);
 95→
 96→  isEditingShared.value = isEditing;
 97→
 98→  useEffect(() => {
 99→    translateX.value = withSpring(isEditing ? ACTION_BUTTON_WIDTH : 0);
100→  }, [isEditing, translateX]);
101→
102→  const triggerDelete = useCallback(() => {
103→    translateX.value = withSpring(0);
104→    onDelete(source.id);
105→  }, [source.id, onDelete, translateX]);
106→
107→  const handleEditPress = useCallback(() => {
108→    if (isEditing) {
109→      onConfirmEdit();
110→    } else {
111→      onStartEdit(source.id);
112→    }
113→  }, [isEditing, onConfirmEdit, onStartEdit, source.id]);
114→
115→  const pan = Gesture.Pan()
116→    .activeOffsetX([-10, 10])
117→    .failOffsetY([-10, 10])
118→    .onStart(() => {
119→      startX.value = translateX.value;
120→    })
121→    .onUpdate((event) => {
122→      const raw = startX.value + event.translationX;
123→      const limit = ACTION_BUTTON_WIDTH * 1.5;
124→      translateX.value = Math.max(-limit, Math.min(limit, raw));
125→    })
126→    .onEnd(() => {
127→      if (isEditingShared.value) {
128→        if (translateX.value < SWIPE_THRESHOLD / 2) {
129→          translateX.value = withSpring(0);
130→          runOnJS(onCancelEdit)();
131→        } else {
132→          translateX.value = withSpring(ACTION_BUTTON_WIDTH);
133→        }
134→      } else {
135→        if (translateX.value < -SWIPE_THRESHOLD) {
136→          translateX.value = withSpring(-ACTION_BUTTON_WIDTH);
137→        } else if (translateX.value > SWIPE_THRESHOLD) {
138→          translateX.value = withSpring(ACTION_BUTTON_WIDTH);
139→        } else {
140→          translateX.value = withSpring(0);
141→        }
142→      }
143→    });
144→
145→  const tap = Gesture.Tap().onEnd(() => {
146→    if (Math.abs(translateX.value) > 10 && !isEditingShared.value) {
147→      translateX.value = withSpring(0);
148→    }
149→  });
150→
151→  const gesture = Gesture.Race(pan, tap);
152→
153→  const contentAnimStyle = useAnimatedStyle(() => ({
154→    transform: [{ translateX: translateX.value }],
155→  }));
156→
157→  const contentBgStyle = useAnimatedStyle(() => {
158→    const absX = Math.abs(translateX.value);
159→    const progress = Math.min(absX / SWIPE_THRESHOLD, 1);
160→    const bgColor = interpolateColor(
161→      progress,
162→      [0, 1],
163→      isDark
164→        ? ["rgba(44,43,45,0)", "#2c2b2d"]
165→        : ["rgba(128,128,128,0)", "rgba(128,128,128,0.12)"]
166→    );
167→    return {
168→      backgroundColor: bgColor,
169→      borderRadius: interpolate(progress, [0, 1], [0, 21]),
170→    };
171→  });
172→
173→  const editButtonWidthStyle = useAnimatedStyle(() => ({
174→    width: translateX.value > BUTTON_GAP ? translateX.value - BUTTON_GAP : 0,
175→    opacity: translateX.value > BUTTON_GAP ? 1 : 0,
176→  }));
177→
178→  const deleteButtonWidthStyle = useAnimatedStyle(() => ({
179→    width: -translateX.value > BUTTON_GAP ? -translateX.value - BUTTON_GAP : 0,
180→    opacity: -translateX.value > BUTTON_GAP ? 1 : 0,
181→  }));
182→
183→  const editScaleStyle = useActionButtonScale(translateX, 1);
184→  const deleteScaleStyle = useActionButtonScale(translateX, -1);
185→
186→  return (
187→    <View style={styles.rowContainer}>
188→      {/* Edit button - left */}
189→      <Animated.View
190→        style={[
191→          styles.actionButtonContainer,
192→          styles.editButtonContainer,
193→          editButtonWidthStyle,
194→        ]}
195→      >
196→        <Pressable
197→          onPress={handleEditPress}
198→          style={styles.actionButtonPressable}
199→          accessibilityRole="button"
200→          accessibilityLabel={
201→            isEditing
202→              ? t("manageBooks.confirmEditAction")
203→              : t("manageBooks.editAction")
204→          }
205→        >
206→          <Animated.View style={[styles.actionButtonContent, editScaleStyle]}>
207→            <View style={[styles.actionButtonIcon, styles.editButtonColor]}>
208→              <MaterialIcons
209→                name={isEditing ? "check" : "edit"}
210→                size={26}
211→                color="#FFFFFF"
212→              />
213→            </View>
214→            <Text numberOfLines={1} style={[styles.actionButtonLabel, { color: colors.textSecondary }]}>
215→              {isEditing
216→                ? t("manageBooks.confirmEditAction")
217→                : t("manageBooks.editAction")}
218→            </Text>
219→          </Animated.View>
220→        </Pressable>
221→      </Animated.View>
222→
223→      {/* Delete button - right */}
224→      <Animated.View
225→        style={[
226→          styles.actionButtonContainer,
227→          styles.deleteButtonContainer,
228→          deleteButtonWidthStyle,
229→        ]}
230→      >
231→        <Pressable
232→          onPress={triggerDelete}
233→          style={styles.actionButtonPressable}
234→          accessibilityRole="button"
235→          accessibilityLabel={t("manageBooks.deleteConfirmAction")}
236→        >
237→          <Animated.View style={[styles.actionButtonContent, deleteScaleStyle]}>
238→            <View style={[styles.actionButtonIcon, styles.deleteButtonColor]}>
239→              <MaterialIcons name="delete" size={26} color="#FFFFFF" />
240→            </View>
241→            <Text numberOfLines={1} style={[styles.actionButtonLabel, { color: colors.textSecondary }]}>
242→              {t("manageBooks.deleteConfirmAction")}
243→            </Text>
244→          </Animated.View>
245→        </Pressable>
246→      </Animated.View>
247→
248→      {/* Content */}
249→      <GestureDetector gesture={gesture}>
