264→              />
265→              <Text
266→                style={[styles.recipeCount, { color: colors.textSecondary }]}
267→              >
268→                {t("manageBooks.recipeCount", { count: recipeCount })}
269→              </Text>
270→            </>
271→          ) : (
272→            <>
273→              <Text style={[styles.bookTitle, { color: textColor }]}>
274→                {source.name}
275→              </Text>
276→              <Text
277→                style={[styles.recipeCount, { color: colors.textSecondary }]}
278→              >
279→                {t("manageBooks.recipeCount", { count: recipeCount })}
280→              </Text>
281→            </>
282→          )}
283→        </Animated.View>
284→      </GestureDetector>
285→
286→    </View>
287→  );
288→}
