290→export default function ManageBooksScreen(): JSX.Element {
291→  const { t } = useTranslation();
292→  const theme = useTheme();
293→  const colors = getColors(theme);
294→  const insets = useSafeAreaInsets();
295→  const isDark = theme === "dark";
296→  const textColor = isDark ? "#FFFFFF" : "#000000";
297→  const { sources, createSource, renameSource, setSourceLanguage, deleteSource } = useSources();
298→  const { recipes, deleteRecipes } = useRecipes();
299→  const { addToQueue } = useBackgroundProcessing();
300→  const isDeletingRef = useRef(false);
301→
302→  const [isAddingBook, setIsAddingBook] = useState(false);
303→  const [newBookName, setNewBookName] = useState("");
304→  const [editingSourceId, setEditingSourceId] = useState<SourceId | null>(null);
305→  const [editText, setEditText] = useState("");
306→
307→  const recipeCounts = useMemo(() => {
308→    const counts = new Map<SourceId, number>();
309→    for (const recipe of recipes) {
310→      const src = recipe.metadata.source;
311→      if (src && !isUrl(src)) {
312→        counts.set(src, (counts.get(src) ?? 0) + 1);
313→      }
314→    }
315→    return counts;
316→  }, [recipes]);
317→
318→  const handleStartAdd = useCallback(() => {
319→    setIsAddingBook(true);
320→    setNewBookName("");
321→  }, []);
322→
323→  const handleCancelAdd = useCallback(() => {
324→    setIsAddingBook(false);
325→    setNewBookName("");
326→  }, []);
327→
328→  const handleConfirmAdd = useCallback(async () => {
329→    const trimmed = newBookName.trim();
330→    if (!trimmed) return;
331→    try {
332→      await createSource(trimmed);
333→      setIsAddingBook(false);
334→      setNewBookName("");
335→    } catch (error) {
336→      const message = error instanceof Error ? error.message : "";
337→      if (!message.includes("already exists") && !message.includes("cannot be empty") && !message.includes("too long")) {
338→        console.warn("Unexpected error adding book:", error);
339→      }
340→    }
341→  }, [newBookName, createSource]);
342→
343→  const handleDeleteBook = useCallback(
344→    (sourceId: SourceId) => {
345→      if (isDeletingRef.current) return;
346→      const source = sources.find((s) => s.id === sourceId);
347→      if (!source) return;
348→      const count = recipeCounts.get(sourceId) ?? 0;
349→
350→      Alert.alert(
351→        t("manageBooks.deleteConfirmTitle", { name: source.name }),
352→        t("manageBooks.deleteConfirmMessage", { count }),
353→        [
354→          { text: t("manageBooks.deleteConfirmCancel"), style: "cancel" },
355→          {
356→            text: t("manageBooks.deleteConfirmAction"),
357→            style: "destructive",
358→            onPress: async () => {
359→              isDeletingRef.current = true;
360→              try {
361→                if (Platform.OS !== "web") {
362→                  Haptics.notificationAsync(
363→                    Haptics.NotificationFeedbackType.Warning
364→                  );
365→                }
366→                const recipesToDelete = recipes.filter(
367→                  (r) => r.metadata.source === sourceId
368→                );
369→                await deleteRecipes(recipesToDelete.map((recipe) => recipe.id));
370→                LayoutAnimation.configureNext(
371→                  LayoutAnimation.Presets.easeInEaseOut
372→                );
373→                await deleteSource(sourceId);
374→              } finally {
375→                isDeletingRef.current = false;
376→              }
377→            },
378→          },
379→        ]
380→      );
381→    },
382→    [sources, recipeCounts, recipes, deleteRecipes, deleteSource, t]
383→  );
384→
385→  const handleStartEdit = useCallback(
386→    (sourceId: SourceId) => {
387→      const source = sources.find((s) => s.id === sourceId);
388→      if (!source) return;
389→      setEditingSourceId(sourceId);
390→      setEditText(source.name);
391→    },
392→    [sources]
393→  );
394→
395→  const handleConfirmEdit = useCallback(async () => {
396→    if (!editingSourceId) return;
397→    const trimmed = editText.trim();
398→    if (trimmed) {
399→      try {
400→        await renameSource(editingSourceId, trimmed);
401→      } catch (error) {
402→        const message = error instanceof Error ? error.message : "";
403→        if (!message.includes("already exists") && !message.includes("cannot be empty") && !message.includes("too long")) {
404→          console.warn("Unexpected error renaming book:", error);
405→        }
406→      }
407→    }
408→    setEditingSourceId(null);
409→    setEditText("");
410→  }, [editingSourceId, editText, renameSource]);
411→
412→  const handleCancelEdit = useCallback(() => {
413→    setEditingSourceId(null);
414→    setEditText("");
415→  }, []);
416→
417→  return (
418→    <View style={[styles.container, { backgroundColor: colors.background }]}>
419→      <View style={[styles.header, { paddingTop: insets.top + 16 }]}>
420→        <Text style={[styles.headerTitle, { color: textColor }]}>
421→          {t("manageBooks.title")}
422→        </Text>
423→      </View>
424→
425→      {sources.length === 0 && !isAddingBook ? (
426→        <View style={styles.emptyState}>
427→          <Text style={[styles.emptyStateText, { color: colors.textSecondary }]}>
428→            {t("manageBooks.emptyState")}
429→          </Text>
430→        </View>
431→      ) : (
432→        <ScrollView
433→          style={styles.list}
434→          contentContainerStyle={styles.listContent}
435→        >
436→          {sources.map((source) => (
437→            <SwipeableBookRow
438→              key={source.id}
439→              source={source}
440→              recipeCount={recipeCounts.get(source.id) ?? 0}
441→              editingSourceId={editingSourceId}
442→              onDelete={handleDeleteBook}
443→              onStartEdit={handleStartEdit}
444→              onConfirmEdit={handleConfirmEdit}
445→              onCancelEdit={handleCancelEdit}
446→              editText={editText}
447→              onEditTextChange={setEditText}
448→            />
449→          ))}
450→        </ScrollView>
451→      )}
452→
453→      <KeyboardAvoidingView
454→        behavior={Platform.OS === "ios" ? "padding" : "height"}
455→        style={styles.keyboardAvoid}
456→      >
457→        <View style={styles.bottomBar}>
458→          {isAddingBook ? (
459→            <>
460→              <LiquidGlassButton
