467→                  value={newBookName}
468→                  onChangeText={setNewBookName}
469→                  placeholder={t("sourceSelector.addNewPlaceholder")}
470→                  variant="text"
471→                  style={styles.addInputField}
472→                  autoFocus
473→                  maxLength={100}
474→                  returnKeyType="done"
475→                  onSubmitEditing={handleConfirmAdd}
476→                />
