    marginTop: 2,
  },
  editInput: {
    flex: 1,
    fontSize: 17,
    fontWeight: "400",
    padding: 0,
    margin: 0,
    marginRight: ACTION_BUTTON_WIDTH,
  },
  actionButtonContainer: {
    position: "absolute",
    top: 0,
    bottom: 0,
    overflow: "hidden",
  },
  editButtonContainer: {
    left: 6,
  },
  deleteButtonContainer: {
    right: 6,
  },
  actionButtonPressable: {
    flex: 1,
    justifyContent: "center",
    alignItems: "center",
  },
  actionButtonContent: {
    width: BUTTON_CONTENT_WIDTH,
    alignItems: "center",
    justifyContent: "center",
  },
  actionButtonIcon: {
    minWidth: 36,
    height: 36,
    alignSelf: "stretch",
    borderRadius: 16,
    justifyContent: "center",
    alignItems: "center",
    marginHorizontal: 4,
  },
  actionButtonLabel: {
    fontSize: 13.5,
    fontWeight: "500",
    marginTop: 4,
  },
  editButtonColor: {
    backgroundColor: "#007AFF",
  },
  deleteButtonColor: {
    backgroundColor: "#FF3B30",
  },
  emptyState: {
    flex: 1,
    justifyContent: "center",
    alignItems: "center",
  },
  emptyStateText: {
    fontSize: 17,
  },
  keyboardAvoid: {
    position: "absolute",
    bottom: 0,
    left: 0,
    right: 0,
  },
  bottomBar: {
    flexDirection: "row",
    alignItems: "center",
    gap: 12,
    paddingHorizontal: 28,
    paddingBottom: 28,
  },
  addInput: {
    flex: 1,
  },
  addInputField: {
    height: 48,
  },
  spacer: {
    flex: 1,
  },
});

