 1→/**
 2→ * Web OCR implementation using Tesseract.js
 3→ * Runs OCR in a Web Worker for off-thread processing
 4→ */
 5→
 6→import type { DataUrl } from "@/lib/types/primitives";
 7→import { createWorker, type Worker } from "tesseract.js";
 8→import type { OcrResult } from "./types";
 9→
10→// Persistent worker instance for reuse across multiple extractions
11→let worker: Worker | null = null;
12→
13→/**
14→ * Extract text from an image using Tesseract.js OCR
15→ * @param imageUri - Data URL of the image to process
16→ * @returns OCR result with extracted text blocks and confidence
17→ */
18→export async function extractText(imageUri: DataUrl): Promise<OcrResult> {
19→  try {
20→    console.log("[OCR Bridge] Starting text extraction (web/tesseract)");
21→
22→    // Lazy initialization: create worker on first use
23→    if (!worker) {
24→      console.log("[OCR Bridge] Initializing Tesseract worker");
25→      try {
26→        worker = await createWorker("eng", 1, {
27→          errorHandler: (err) =>
28→            console.error("[OCR Bridge] Worker error:", err),
29→        });
30→        console.log("[OCR Bridge] Tesseract worker ready");
31→      } catch (workerError) {
32→        console.error(
33→          "[OCR Bridge] Failed to create Tesseract worker:",
34→          workerError
35→        );
36→        return {
37→          success: false,
38→          error: `Worker initialization failed: ${
39→            workerError instanceof Error ? workerError.message : "Unknown error"
40→          }`,
41→        };
42→      }
43→    }
44→
45→    // Perform OCR recognition
46→    const { data } = await worker.recognize(imageUri);
47→
48→    if (!data.text || data.text.trim().length === 0) {
49→      console.log("[OCR Bridge] No text detected in image");
50→      return {
51→        success: true,
52→        text: "",
53→        textBlocks: [],
54→        confidence: 0,
55→      };
56→    }
57→
58→    // Extract text blocks from Tesseract result
59→    const textBlocks = data.blocks
60→      ?.map((block) => block.text)
61→      .filter((text) => text.trim()) ?? [data.text];
62→
63→    // Normalize confidence from 0-100 to 0-1
64→    const confidence = data.confidence / 100;
65→
66→    console.log(
67→      `[OCR Bridge] Text extraction complete: ${textBlocks.length} blocks, ${
68→        data.text.length
69→      } characters, ${Math.round(confidence * 100)}% confidence`
70→    );
71→
72→    return {
73→      success: true,
74→      text: data.text,
75→      textBlocks,
76→      confidence,
