  1→import * as Crypto from "expo-crypto";
  2→import { storage } from "../storage";
  3→import type { StorageKey, TagId } from "../types/primitives";
  4→import type { Tag } from "../types/tag";
  5→
  6→const TAGS_KEY: StorageKey = "@tags";
  7→
  8→let lockChain = Promise.resolve();
  9→
 10→function withLock<T>(fn: () => Promise<T>): Promise<T> {
 11→  const next = lockChain.then(fn, fn);
 12→  lockChain = next.then(() => {}, () => {});
 13→  return next;
 14→}
 15→
 16→function normalizeLabel(label: string): { label: `#${string}`; normalizedLabel: string } | null {
 17→  const trimmed = label.trim();
 18→  const withoutHash = trimmed.replace(/^#+/, "");
 19→
 20→  if (!withoutHash || /\s/.test(withoutHash)) {
 21→    return null;
 22→  }
 23→
 24→  const normalizedLabel = withoutHash.toLowerCase();
 25→
 26→  return {
 27→    label: `#${normalizedLabel}`,
 28→    normalizedLabel,
 29→  };
 30→}
 31→
 32→function dedupeTagIds(tagIds: Array<TagId>): Array<TagId> {
 33→  return Array.from(new Set(tagIds));
 34→}
 35→
 36→function computeDiff(
 37→  prevTagIds: Array<TagId>,
 38→  nextTagIds: Array<TagId>
 39→): { removed: Array<TagId>; added: Array<TagId> } {
 40→  const prevSet = new Set(dedupeTagIds(prevTagIds));
 41→  const nextSet = new Set(dedupeTagIds(nextTagIds));
 42→
 43→  const removed = Array.from(prevSet).filter((tagId) => !nextSet.has(tagId));
 44→  const added = Array.from(nextSet).filter((tagId) => !prevSet.has(tagId));
 45→
 46→  return { removed, added };
 47→}
 48→
 49→type RecipeTagDiff = {
 50→  prevTagIds: Array<TagId>;
 51→  nextTagIds: Array<TagId>;
 52→};
 53→
 54→type TagResolutionInput = {
 55→  nextTagIds?: Array<TagId>;
 56→  nextLabels?: Array<string>;
 57→};
 58→
 59→type PrevTagIdsInput = Array<TagId> | (() => Promise<Array<TagId>>);
 60→
 61→class TagsRepository {
 62→  private async readAll(): Promise<Array<Tag>> {
 63→    const data = await storage.getItem(TAGS_KEY);
 64→    if (!data) {
 65→      return [];
 66→    }
 67→
 68→    try {
 69→      const parsed = JSON.parse(data) as Array<Tag>;
 70→      return parsed.filter(
 71→        (tag) =>
 72→          typeof tag?.id === "string" &&
 73→          typeof tag?.label === "string" &&
 74→          typeof tag?.normalizedLabel === "string" &&
 75→          typeof tag?.recipeCount === "number" &&
 76→          typeof tag?.lastUsedAt === "number"
 77→      );
 78→    } catch {
 79→      return [];
 80→    }
 81→  }
 82→
 83→  private async writeAll(tags: Array<Tag>): Promise<void> {
 84→    await storage.setItem(TAGS_KEY, JSON.stringify(tags));
 85→  }
 86→
 87→  async getAll(): Promise<Array<Tag>> {
 88→    return this.readAll();
 89→  }
 90→
 91→  async getById(id: TagId): Promise<Tag | null> {
 92→    const tags = await this.readAll();
 93→    return tags.find((tag) => tag.id === id) ?? null;
 94→  }
 95→
 96→  async getByIds(ids: Array<TagId>): Promise<Array<Tag>> {
 97→    const tags = await this.readAll();
 98→    const tagsById = new Map(tags.map((tag) => [tag.id, tag]));
 99→    return dedupeTagIds(ids)
100→      .map((id) => tagsById.get(id))
101→      .filter((tag): tag is Tag => tag !== undefined);
102→  }
103→
104→  async findByNormalized(normalized: string): Promise<Tag | null> {
105→    const normalizedLabel = normalizeLabel(normalized)?.normalizedLabel;
106→    if (!normalizedLabel) {
107→      return null;
108→    }
109→
110→    const tags = await this.readAll();
111→    return tags.find((tag) => tag.normalizedLabel === normalizedLabel) ?? null;
112→  }
113→
114→  async mutateRecipeTags<T>(
115→    input: {
116→      prevTagIds: PrevTagIdsInput;
117→      nextTagIds?: Array<TagId>;
118→      nextLabels?: Array<string>;
119→    },
120→    commitRecipe: (resolvedNextTagIds: Array<TagId>) => Promise<T>
121→  ): Promise<T> {
122→    return withLock(async () => {
123→      const prevTagIds =
124→        typeof input.prevTagIds === "function"
125→          ? await input.prevTagIds()
126→          : input.prevTagIds;
127→      const tags = await this.readAll();
128→      const resolvedNextTagIds = this.resolveNextTagIds(tags, {
129→        nextTagIds: input.nextTagIds,
130→        nextLabels: input.nextLabels,
131→      });
132→      const result = await commitRecipe(resolvedNextTagIds);
133→
134→      this.applyDiffs(tags, [
135→        {
136→          prevTagIds,
137→          nextTagIds: resolvedNextTagIds,
138→        },
139→      ]);
140→      this.pruneZeroCountTags(tags);
141→      await this.writeAll(tags);
142→
143→      return result;
144→    });
145→  }
146→
147→  async mutateMultipleRecipeDiffs<T>(
148→    commitRecipe: () => Promise<{
149→      result: T;
150→      diffs: Array<RecipeTagDiff>;
151→    }>
152→  ): Promise<T> {
153→    return withLock(async () => {
154→      const tags = await this.readAll();
155→      const { result, diffs } = await commitRecipe();
156→      this.applyDiffs(tags, diffs);
157→      this.pruneZeroCountTags(tags);
158→      await this.writeAll(tags);
159→      return result;
160→    });
161→  }
162→
163→  private resolveNextTagIds(
164→    tags: Array<Tag>,
165→    input: TagResolutionInput
166→  ): Array<TagId> {
167→    if (input.nextLabels !== undefined) {
168→      const tagsByNormalized = new Map(
169→        tags.map((tag) => [tag.normalizedLabel, tag])
170→      );
171→      const now = Date.now();
172→      const normalizedLabels = Array.from(
173→        new Set(
174→          input.nextLabels
175→            .map((label) => normalizeLabel(label))
176→            .filter(
177→              (
178→                normalized
179→              ): normalized is {
180→                label: `#${string}`;
181→                normalizedLabel: string;
182→              } => normalized !== null
183→            )
184→            .map((normalized) => normalized.normalizedLabel)
185→        )
186→      );
187→
188→      if (normalizedLabels.length === 0) {
189→        return [];
190→      }
191→
192→      const resolvedTagIds: Array<TagId> = [];
193→
194→      for (const normalizedLabel of normalizedLabels) {
195→        const existing = tagsByNormalized.get(normalizedLabel);
196→        if (existing) {
197→          existing.lastUsedAt = now;
198→          resolvedTagIds.push(existing.id);
199→          continue;
200→        }
201→
202→        const created: Tag = {
203→          id: Crypto.randomUUID(),
204→          label: `#${normalizedLabel}`,
205→          normalizedLabel,
206→          recipeCount: 0,
207→          lastUsedAt: now,
208→        };
209→        tags.push(created);
210→        tagsByNormalized.set(normalizedLabel, created);
211→        resolvedTagIds.push(created.id);
212→      }
213→
214→      return resolvedTagIds;
215→    }
216→
217→    return dedupeTagIds(input.nextTagIds ?? []);
218→  }
219→
220→  private applyDiffs(tags: Array<Tag>, diffs: Array<RecipeTagDiff>): void {
221→    const tagsById = new Map(tags.map((tag) => [tag.id, tag]));
222→    const now = Date.now();
223→
224→    for (const diff of diffs) {
225→      const { removed, added } = computeDiff(diff.prevTagIds, diff.nextTagIds);
226→
227→      for (const tagId of removed) {
228→        const tag = tagsById.get(tagId);
229→        if (!tag) {
230→          continue;
231→        }
232→
233→        tag.recipeCount = Math.max(0, tag.recipeCount - 1);
234→      }
235→
236→      for (const tagId of added) {
237→        const tag = tagsById.get(tagId);
238→        if (!tag) {
239→          continue;
240→        }
241→
242→        tag.recipeCount += 1;
243→        tag.lastUsedAt = now;
244→      }
245→    }
246→
247→  }
248→
249→  private pruneZeroCountTags(tags: Array<Tag>): void {
250→    for (let index = tags.length - 1; index >= 0; index -= 1) {
251→      if (tags[index].recipeCount <= 0) {
252→        tags.splice(index, 1);
253→      }
254→    }
255→  }
256→}
