  1→/**
  2→ * Background Processing Context
  3→ * Manages a queue of pending recipe processing tasks
  4→ * Persists state across navigation and app restarts
  5→ */
  6→
  7→import { useRecipes } from "@/features/recipes-list/context/RecipesContext";
  8→import { useSources } from "@/features/sources/context/SourcesContext";
  9→import { processPhoto } from "@/lib/photo-processor";
 10→import { DEFAULT_CONFIG } from "@/lib/photo-processor/types";
 11→import { loadImageAsDataUrl } from "@/lib/photo-processor/utils/loadImageAsDataUrl";
 12→import { recipeRepository } from "@/lib/repositories/recipes";
 13→import { storage } from "@/lib/storage";
 14→import { classifyText } from "@/lib/text-classifier";
 15→import type { AppLanguage } from "@/lib/types/language";
 16→import type { RecipeId } from "@/lib/types/primitives";
 17→import { isUrl } from "@/lib/utils/recipeValidation";
 18→import {
 19→  createContext,
 20→  useCallback,
 21→  useContext,
 22→  useEffect,
 23→  useMemo,
 24→  useRef,
 25→  useState,
 26→  type JSX,
 27→  type ReactNode,
 28→} from "react";
 29→
 30→interface ProcessingProgress {
 31→  recipeId: RecipeId;
 32→  phase: "geometry" | "lighting" | "clarity" | "ocr" | "classification";
 33→  progress: number;
 34→}
 35→
 36→interface BackgroundProcessingContextValue {
 37→  addToQueue: (recipeId: RecipeId) => void;
 38→  isProcessing: (recipeId: RecipeId) => boolean;
 39→  processingProgress: (recipeId: RecipeId) => ProcessingProgress | null;
 40→  currentlyProcessing: RecipeId | null;
 41→}
 42→
 43→const BackgroundProcessingContext =
 44→  createContext<BackgroundProcessingContextValue | null>(null);
 45→
 46→export function BackgroundProcessingProvider({
 47→  children,
 48→}: {
 49→  children: ReactNode;
 50→}): JSX.Element {
 51→  const { updateProcessing, updateComplete } = useRecipes();
 52→  const { sources } = useSources();
 53→  const [queue, setQueue] = useState<Array<RecipeId>>([]);
 54→  const [currentlyProcessing, setCurrentlyProcessing] =
 55→    useState<RecipeId | null>(null);
 56→  const [progress, setProgress] = useState<Map<RecipeId, ProcessingProgress>>(
 57→    new Map()
 58→  );
 59→  const isProcessingRef = useRef(false);
 60→
 61→  const addToQueue = useCallback((recipeId: RecipeId): void => {
 62→    setQueue((prev) => {
 63→      if (prev.includes(recipeId)) {
 64→        return prev;
 65→      }
 66→      return [...prev, recipeId];
 67→    });
 68→  }, []);
 69→
 70→  const isProcessing = useCallback(
 71→    (recipeId: RecipeId): boolean => {
 72→      return currentlyProcessing === recipeId || queue.includes(recipeId);
 73→    },
 74→    [currentlyProcessing, queue]
 75→  );
 76→
 77→  const processingProgress = useCallback(
 78→    (recipeId: RecipeId): ProcessingProgress | null => {
 79→      return progress.get(recipeId) || null;
 80→    },
 81→    [progress]
 82→  );
 83→
 84→  const updateProgress = useCallback(
 85→    (
 86→      recipeId: RecipeId,
 87→      phase: ProcessingProgress["phase"],
 88→      progressValue: number
 89→    ): void => {
 90→      setProgress(
 91→        (prev) =>
 92→          new Map(
 93→            prev.set(recipeId, {
 94→              recipeId,
 95→              phase,
 96→              progress: progressValue,
 97→            })
 98→          )
 99→      );
100→    },
101→    []
102→  );
103→
104→  const processRecipe = useCallback(
105→    async (recipeId: RecipeId): Promise<void> => {
106→      try {
107→        console.log(
108→          `[Background Processing] Starting processing for ${recipeId}`
109→        );
110→
111→        await updateProcessing(recipeId);
112→        setCurrentlyProcessing(recipeId);
113→
114→        const recipe = await recipeRepository.getById(recipeId);
115→        if (!recipe) {
116→          console.error(`[Background Processing] Recipe ${recipeId} not found`);
117→          return;
118→        }
119→
120→        const photoUri = await storage.getPhoto(recipeId);
121→        if (!photoUri) {
122→          console.error(
123→            `[Background Processing] Photo not found in storage for ${recipeId}`
124→          );
125→          return;
126→        }
127→
128→        const photoDataUrl = await loadImageAsDataUrl(photoUri);
129→
130→        // Look up book language for OCR
131→        let ocrLanguage: AppLanguage = "en";
132→        const sourceId = recipe.metadata.source;
133→        if (sourceId && !isUrl(sourceId)) {
134→          const source = sources.find((s) => s.id === sourceId);
135→          if (source) {
136→            ocrLanguage = source.language;
137→          }
138→        }
139→
140→        updateProgress(recipeId, "geometry", 0);
141→
142→        const result = await processPhoto(photoDataUrl, {
143→          ...DEFAULT_CONFIG,
144→          geometry: {
145→            ...DEFAULT_CONFIG.geometry,
146→            enabled: true,
147→          },
148→          lighting: {
149→            ...DEFAULT_CONFIG.lighting,
150→            enabled: true,
151→          },
152→          clarity: {
153→            ...DEFAULT_CONFIG.clarity,
154→            enabled: true,
155→          },
156→          ocr: {
157→            enabled: true,
158→            language: ocrLanguage,
159→          },
160→        });
161→
162→        if (!result.success || !result.processedUri) {
163→          console.error(
164→            `[Background Processing] Processing failed for ${recipeId}:`,
165→            result.error
166→          );
167→          await updateComplete(recipeId, photoUri);
168→          return;
169→        }
170→
171→        updateProgress(recipeId, "ocr", 80);
172→
173→        let classificationResult;
174→        if (result.ocrResult?.text) {
175→          updateProgress(recipeId, "classification", 90);
176→
177→          try {
178→            classificationResult = await classifyText(
179→              result.ocrResult.text,
180→              "embeddings"
181→            );
182→
183→            if (classificationResult.suggestions.length === 0) {
184→              classificationResult = await classifyText(
185→                result.ocrResult.text,
186→                "tfidf"
187→              );
188→            }
189→          } catch (error) {
190→            console.warn(
191→              `[Background Processing] Classification failed for ${recipeId}:`,
192→              error
193→            );
194→          }
195→        }
196→
197→        updateProgress(recipeId, "classification", 95);
198→
199→        const tags = classificationResult?.suggestions
200→          ? classificationResult.suggestions
201→              .map((s) => s.tag)
202→              .filter(
203→                (tag): tag is `#${string}` =>
204→                  typeof tag === "string" && tag.startsWith("#")
205→              )
206→          : [];
207→
208→        await updateComplete(
209→          recipeId,
210→          result.processedUri,
211→          result.ocrResult?.text,
212→          {
213→            title: classificationResult?.title,
214→            tags,
215→          }
216→        );
217→
218→        updateProgress(recipeId, "classification", 100);
219→        console.log(
220→          `[Background Processing] Completed processing for ${recipeId}`
221→        );
222→      } catch (error) {
223→        console.error(
224→          `[Background Processing] Error processing ${recipeId}:`,
225→          error
226→        );
227→      } finally {
228→        setCurrentlyProcessing(null);
229→        setProgress((prev) => {
230→          const next = new Map(prev);
231→          next.delete(recipeId);
232→          return next;
233→        });
234→      }
235→    },
236→    [updateProgress, updateProcessing, updateComplete, sources]
237→  );
238→
239→  useEffect(() => {
240→    async function resumePendingRecipes(): Promise<void> {
241→      try {
242→        const pendingRecipes = await recipeRepository.getPendingRecipes();
243→        const pendingIds = pendingRecipes.map((r) => r.id);
244→
245→        if (pendingIds.length > 0) {
246→          console.log(
247→            `[Background Processing] Resuming ${pendingIds.length} pending recipe(s)`
248→          );
249→          setQueue(pendingIds);
250→        }
251→      } catch (error) {
252→        console.error(
253→          "[Background Processing] Failed to resume pending recipes:",
254→          error
255→        );
256→      }
257→    }
258→
259→    resumePendingRecipes();
260→  }, []);
261→
262→  useEffect(() => {
263→    async function processQueue(): Promise<void> {
264→      if (isProcessingRef.current || queue.length === 0) {
265→        return;
266→      }
267→
268→      isProcessingRef.current = true;
269→      const recipeId = queue[0];
270→
271→      await processRecipe(recipeId);
272→
273→      setQueue((prev) => prev.slice(1));
274→      isProcessingRef.current = false;
275→    }
276→
277→    processQueue();
278→  }, [queue, processRecipe]);
279→
280→  const value = useMemo(
281→    (): BackgroundProcessingContextValue => ({
282→      addToQueue,
283→      isProcessing,
284→      processingProgress,
285→      currentlyProcessing,
286→    }),
287→    [addToQueue, isProcessing, processingProgress, currentlyProcessing]
288→  );
289→
290→  return (
291→    <BackgroundProcessingContext.Provider value={value}>
292→      {children}
293→    </BackgroundProcessingContext.Provider>
294→  );
295→}
296→
297→export function useBackgroundProcessing(): BackgroundProcessingContextValue {
298→  const context = useContext(BackgroundProcessingContext);
299→  if (!context) {
300→    throw new Error(
301→      "useBackgroundProcessing must be used within BackgroundProcessingProvider"
302→    );
303→  }
304→  return context;
305→}
