  1→import * as Crypto from "expo-crypto";
  2→import { storage } from "../storage";
  3→import type { PhotoUri, RecipeId, SourceId, StorageKey, TagId } from "../types/primitives";
  4→import type { Recipe } from "../types/recipe";
  5→import { migrateIfNeeded } from "./photosToRecipesMigration";
  6→import { tagsRepository } from "./tags";
  7→import type { RecipeMetadataWrite, RecipeRepository } from "./types";
  8→
  9→const RECIPES_KEY: StorageKey = "@recipes";
 10→
 11→function stripRuntimeFields(recipe: Recipe): Recipe {
 12→  // eslint-disable-next-line @typescript-eslint/no-unused-vars
 13→  const { thumbnailUri, ...persisted } = recipe;
 14→  return { ...persisted, photoUri: persisted.id };
 15→}
 16→
 17→function dedupeTagIds(tagIds: Array<TagId>): Array<TagId> {
 18→  return Array.from(new Set(tagIds));
 19→}
 20→
 21→function normalizeRecipe(recipe: Recipe): Recipe {
 22→  return {
 23→    ...recipe,
 24→    photoUri: recipe.photoUri || recipe.id,
 25→    status: recipe.status || "ready",
 26→    metadata: {
 27→      ...recipe.metadata,
 28→      tagIds: Array.isArray(recipe.metadata?.tagIds)
 29→        ? dedupeTagIds(recipe.metadata.tagIds)
 30→        : [],
 31→    },
 32→  };
 33→}
 34→
 35→class AsyncStorageRecipeRepository implements RecipeRepository {
 36→  private async readPersistedRecipes(): Promise<Array<Recipe>> {
 37→    await migrateIfNeeded(RECIPES_KEY);
 38→
 39→    const data = await storage.getItem(RECIPES_KEY);
 40→    if (!data) {
 41→      return [];
 42→    }
 43→
 44→    try {
 45→      const recipes = JSON.parse(data) as Array<Recipe>;
 46→      return recipes.map(normalizeRecipe);
 47→    } catch {
 48→      return [];
 49→    }
 50→  }
 51→
 52→  private async writePersistedRecipes(recipes: Array<Recipe>): Promise<void> {
 53→    await storage.setItem(
 54→      RECIPES_KEY,
 55→      JSON.stringify(recipes.map(stripRuntimeFields))
 56→    );
 57→  }
 58→
 59→  private async withRuntimeUris(recipes: Array<Recipe>): Promise<Array<Recipe>> {
 60→    const recipesWithUris = await Promise.all(
 61→      recipes.map(async (recipe): Promise<Recipe> => {
 62→        const photoUri = await storage.getPhoto(recipe.id);
 63→        const thumbnailUri = await storage.getThumbnail(recipe.id);
 64→        const finalPhotoUri = photoUri || recipe.photoUri || recipe.id;
 65→
 66→        return {
 67→          ...recipe,
 68→          photoUri: finalPhotoUri,
 69→          thumbnailUri: thumbnailUri || finalPhotoUri,
 70→        };
 71→      })
 72→    );
 73→
 74→    return recipesWithUris;
 75→  }
 76→
 77→  private getTagResolutionInput(
 78→    metadata: Partial<RecipeMetadataWrite>
 79→  ): { nextTagIds?: Array<TagId>; nextLabels?: Array<string> } | null {
 80→    if (metadata.tags !== undefined) {
 81→      return { nextLabels: metadata.tags };
 82→    }
 83→
 84→    if (metadata.tagIds !== undefined) {
 85→      return { nextTagIds: dedupeTagIds(metadata.tagIds) };
 86→    }
 87→
 88→    return null;
 89→  }
 90→
 91→  async getAll(): Promise<Array<Recipe>> {
 92→    const recipes = await this.readPersistedRecipes();
 93→    const recipesWithUris = await this.withRuntimeUris(recipes);
 94→    return recipesWithUris.sort((a, b) => b.timestamp - a.timestamp);
 95→  }
 96→
 97→  async getById(id: RecipeId): Promise<Recipe | null> {
 98→    const recipes = await this.getAll();
 99→    return recipes.find((recipe) => recipe.id === id) ?? null;
100→  }
101→
102→  async save(
103→    recipe: Omit<Recipe, "id" | "timestamp" | "metadata"> & {
104→      metadata: RecipeMetadataWrite;
105→    }
106→  ): Promise<Recipe> {
107→    const id = Crypto.randomUUID();
108→    const timestamp = Date.now();
109→    const tagResolutionInput = this.getTagResolutionInput(recipe.metadata) ?? {
110→      nextTagIds: [],
111→    };
112→
113→    await storage.savePhoto(id, recipe.photoUri, timestamp);
114→
115→    const newRecipe = await tagsRepository.mutateRecipeTags(
116→      {
117→        prevTagIds: [],
118→        ...tagResolutionInput,
119→      },
120→      async (resolvedNextTagIds): Promise<Recipe> => {
121→        const recipeToSave: Recipe = {
122→          id,
123→          photoUri: id,
124→          originalPhotoUri: recipe.originalPhotoUri,
125→          timestamp,
126→          metadata: {
127→            title: recipe.metadata.title,
128→            source: recipe.metadata.source,
129→            tagIds: resolvedNextTagIds,
130→          },
131→          recognizedText: recipe.recognizedText,
132→          status: recipe.status || "ready",
133→        };
134→
135→        const recipes = await this.readPersistedRecipes();
136→        recipes.push(recipeToSave);
137→        await this.writePersistedRecipes(recipes);
138→
139→        return recipeToSave;
140→      }
141→    );
142→
143→    const photoUri = await storage.getPhoto(id);
144→    const finalPhotoUri = photoUri || id;
145→
146→    try {
147→      await storage.saveThumbnail(id, finalPhotoUri);
148→    } catch {
149→      // Thumbnail failure must not break save
150→    }

150→    }
151→
152→    return {
153→      ...newRecipe,
154→      photoUri: finalPhotoUri,
155→    };
156→  }
157→
158→  async update(id: RecipeId, metadata: RecipeMetadataWrite): Promise<Recipe> {
159→    const recipes = await this.readPersistedRecipes();
160→    const index = recipes.findIndex((recipe) => recipe.id === id);
161→
162→    if (index === -1) {
163→      throw new Error(`Recipe with id ${id} not found`);
164→    }
165→
166→    const previousTagIds = recipes[index].metadata.tagIds;
167→    const shouldUpdateTags =
168→      metadata.tags !== undefined || metadata.tagIds !== undefined;
169→
170→    if (!shouldUpdateTags) {
171→      recipes[index] = {
172→        ...recipes[index],
173→        metadata: {
174→          title: metadata.title,
175→          source: metadata.source,
176→          tagIds: previousTagIds,
177→        },
178→      };
179→
180→      await this.writePersistedRecipes(recipes);
181→
182→      const runtimeRecipes = await this.withRuntimeUris([recipes[index]]);
183→      return runtimeRecipes[0];
184→    }
185→
186→    const tagResolutionInput = this.getTagResolutionInput(metadata);
187→    if (!tagResolutionInput) {
188→      throw new Error("Tag resolution input required when updating tags");
189→    }
190→
191→    const updatedRecipe = await tagsRepository.mutateRecipeTags(
192→      {
193→        prevTagIds: async (): Promise<Array<TagId>> => {
194→          const latestRecipes = await this.readPersistedRecipes();
195→          const latestIndex = latestRecipes.findIndex((recipe) => recipe.id === id);
196→
197→          if (latestIndex === -1) {
198→            throw new Error(`Recipe with id ${id} not found`);
199→          }
200→
201→          return latestRecipes[latestIndex].metadata.tagIds;
202→        },
203→        ...tagResolutionInput,
204→      },
205→      async (resolvedNextTagIds): Promise<Recipe> => {
206→        const latestRecipes = await this.readPersistedRecipes();
207→        const latestIndex = latestRecipes.findIndex((recipe) => recipe.id === id);
208→
209→        if (latestIndex === -1) {
210→          throw new Error(`Recipe with id ${id} not found`);
211→        }
212→
213→        latestRecipes[latestIndex] = {
214→          ...latestRecipes[latestIndex],
215→          metadata: {
216→            title: metadata.title,
217→            source: metadata.source,
218→            tagIds: resolvedNextTagIds,
219→          },
220→        };
221→
222→        await this.writePersistedRecipes(latestRecipes);
223→        return latestRecipes[latestIndex];
224→      }
225→    );
226→
227→    const runtimeRecipes = await this.withRuntimeUris([updatedRecipe]);
228→    return runtimeRecipes[0];
229→  }
230→
231→  async delete(id: RecipeId): Promise<void> {
232→    const recipes = await this.readPersistedRecipes();
233→    const recipe = recipes.find((item) => item.id === id);
234→    const filtered = recipes.filter((item) => item.id !== id);
235→
236→    await storage.deletePhoto(id);
237→    await storage.deleteThumbnail(id);
238→
239→    if (!recipe) {
