 46→    [prefix]
 47→  );
 48→
 49→  const tagsById = useMemo((): Map<TagId, Tag> => {
 50→    return new Map(tags.map((tag) => [tag.id, tag]));
 51→  }, [tags]);
 52→
 53→  const excludedTagIdSet = useMemo((): Set<TagId> => {
 54→    return new Set(excludedTagIds);
 55→  }, [excludedTagIds]);
 56→
 57→  const suggestions = useMemo((): Array<TagSuggestion> => {
 58→    return tags
 59→      .filter((tag) => !excludedTagIdSet.has(tag.id))
 60→      .filter((tag) => {
 61→        if (normalizedPrefix.length === 0) {
 62→          return true;
 63→        }
 64→
 65→        const localizedLabel = getTagDisplayLabel(tag.normalizedLabel, uiLanguage);
 66→        return (
 67→          tag.normalizedLabel.startsWith(normalizedPrefix) ||
 68→          localizedLabel.toLowerCase().startsWith(normalizedPrefix)
 69→        );
 70→      })
 71→      .sort((left, right) => {
 72→        if (left.recipeCount !== right.recipeCount) {
 73→          return right.recipeCount - left.recipeCount;
 74→        }
 75→
 76→        return left.normalizedLabel.localeCompare(right.normalizedLabel);
 77→      })
 78→      .slice(0, MAX_SUGGESTIONS)
 79→      .map((tag) => ({
 80→        id: tag.id,
 81→        label: getTagDisplayLabel(tag.normalizedLabel, uiLanguage),
 82→        recipeCount: tag.recipeCount,
 83→        countLabel: formatCount(tag.recipeCount),
 84→      }));
 85→  }, [tags, normalizedPrefix, excludedTagIdSet, uiLanguage]);
 86→
 87→  const handleSuggestionPress = useCallback(
 88→    (id: TagId): void => {
 89→      const tag = tagsById.get(id);
 90→      if (!tag) {
 91→        return;
 92→      }
 93→
 94→      onSelectSuggestion(tag);
 95→    },
 96→    [tagsById, onSelectSuggestion]
 97→  );
 98→
 99→  return useMemo(
100→    (): {
101→      suggestions: Array<TagSuggestion>;
102→      handleSuggestionPress: (id: TagId) => void;
103→    } => ({
104→      suggestions,
105→      handleSuggestionPress,
106→    }),
107→    [suggestions, handleSuggestionPress]
108→  );
109→}
