27→export function useSearchQuery(): {
28→  query: SearchQuery;
29→  addTagFromSuggestion: (tag: Tag) => void;
30→  removeSelectedTag: (tagId: TagId) => void;
31→  setFreeText: (freeText: string) => void;
32→  clearQuery: () => void;
33→} {
34→  const [selectedTags, setSelectedTags] = useState<Array<SearchQueryTag>>([]);
35→  const [freeText, setFreeTextState] = useState("");
36→
37→  const addTagFromSuggestion = useCallback((tag: Tag): void => {
38→    setSelectedTags((previousTags) => {
39→      if (previousTags.some((previousTag) => previousTag.id === tag.id)) {
40→        return previousTags;
41→      }
42→
43→      return [
44→        ...previousTags,
45→        {
46→          id: tag.id,
47→          label: tag.label.replace(/^#/, ""),
48→        },
49→      ];
50→    });
51→    setFreeTextState("");
52→  }, []);
53→
54→  const setFreeText = useCallback((nextFreeText: string): void => {
55→    setFreeTextState(nextFreeText);
56→  }, []);
57→
58→  const removeSelectedTag = useCallback((tagId: TagId): void => {
59→    setSelectedTags((previousTags) =>
60→      previousTags.filter((previousTag) => previousTag.id !== tagId)
61→    );
62→  }, []);
63→
64→  const clearQuery = useCallback((): void => {
65→    setSelectedTags([]);
66→    setFreeTextState("");
67→  }, []);
68→
69→  const suggestionPrefix = useMemo((): string => {
70→    return extractSuggestionPrefix(freeText);
71→  }, [freeText]);
72→
73→  const query = useMemo(
74→    (): SearchQuery => ({
75→      selectedTags,
76→      freeText,
77→      suggestionPrefix,
78→    }),
79→    [selectedTags, freeText, suggestionPrefix]
80→  );
81→
82→  return useMemo(
83→    (): {
84→      query: SearchQuery;
85→      addTagFromSuggestion: (tag: Tag) => void;
86→      removeSelectedTag: (tagId: TagId) => void;
87→      setFreeText: (freeText: string) => void;
88→      clearQuery: () => void;
89→    } => ({
90→      query,
91→      addTagFromSuggestion,
92→      removeSelectedTag,
93→      setFreeText,
94→      clearQuery,
95→    }),
96→    [query, addTagFromSuggestion, removeSelectedTag, setFreeText, clearQuery]
97→  );
98→}
