  1→import { usePreferences } from "@/features/settings/context/PreferencesContext";
  2→import { getTagDisplayLabel } from "@/features/tags/utils/tagDisplayLabels";
  3→import type { TagId } from "@/lib/types/primitives";
  4→import type { Tag } from "@/lib/types/tag";
  5→import { useCallback, useMemo } from "react";
  6→
  7→const MAX_SUGGESTIONS = 5;
  8→
  9→export type TagSuggestion = {
 10→  id: TagId;
 11→  label: string;
 12→  recipeCount: number;
 13→  countLabel: string;
 14→};
 15→
 16→function normalizePrefix(prefix: string): string {
 17→  return prefix.trim().replace(/^#+/, "").toLowerCase();
 18→}
 19→
 20→function formatCount(recipeCount: number): string {
 21→  if (recipeCount > 99) {
 22→    return "99+";
 23→  }
 24→
 25→  return String(recipeCount);
 26→}
 27→
 28→export function useTagSuggestions({
 29→  tags,
 30→  prefix,
 31→  onSelectSuggestion,
 32→  excludedTagIds = [],
 33→}: {
 34→  tags: Array<Tag>;
 35→  prefix: string;
 36→  onSelectSuggestion: (tag: Tag) => void;
 37→  excludedTagIds?: Array<TagId>;
 38→}): {
 39→  suggestions: Array<TagSuggestion>;
 40→  handleSuggestionPress: (id: TagId) => void;
 41→} {
 42→  const { uiLanguage } = usePreferences();
 43→
 44→  const normalizedPrefix = useMemo(
 45→    (): string => normalizePrefix(prefix),
 46→    [prefix]
 47→  );
 48→
 49→  const tagsById = useMemo((): Map<TagId, Tag> => {
 50→    return new Map(tags.map((tag) => [tag.id, tag]));
 51→  }, [tags]);
 52→
 53→  const excludedTagIdSet = useMemo((): Set<TagId> => {
 54→    return new Set(excludedTagIds);
 55→  }, [excludedTagIds]);
 56→
 57→  const suggestions = useMemo((): Array<TagSuggestion> => {
 58→    return tags
 59→      .filter((tag) => !excludedTagIdSet.has(tag.id))
 60→      .filter((tag) => {
 61→        if (normalizedPrefix.length === 0) {
 62→          return true;
 63→        }
 64→
 65→        const localizedLabel = getTagDisplayLabel(tag.normalizedLabel, uiLanguage);
 66→        return (
 67→          tag.normalizedLabel.startsWith(normalizedPrefix) ||
 68→          localizedLabel.toLowerCase().startsWith(normalizedPrefix)
 69→        );
 70→      })
 71→      .sort((left, right) => {
 72→        if (left.recipeCount !== right.recipeCount) {
 73→          return right.recipeCount - left.recipeCount;
 74→        }
 75→
 76→        return left.normalizedLabel.localeCompare(right.normalizedLabel);
 77→      })
 78→      .slice(0, MAX_SUGGESTIONS)
 79→      .map((tag) => ({
 80→        id: tag.id,
 81→        label: getTagDisplayLabel(tag.normalizedLabel, uiLanguage),
 82→        recipeCount: tag.recipeCount,
 83→        countLabel: formatCount(tag.recipeCount),
 84→      }));
