export function RecipeMetadataDisplay({
  metadata,
  style,
}: {
  metadata: RecipeMetadata;
  style?: object;
}): JSX.Element | null {
  const { tagLookup } = useTags();
  const { uiLanguage } = usePreferences();
  const { t } = useTranslation();
  const tagLabels = resolveLocalizedTagLabels(metadata.tagIds, tagLookup, uiLanguage);
  const hasTags = tagLabels.length > 0;
  const hasSource = !!metadata.source;

  if (!hasTags && !hasSource) {
    return (
      <View style={[styles.container, style]}>
