 41→function useActionButtonScale(
 42→  translateX: SharedValue<number>,
 43→  sign: 1 | -1
 44→): { transform: Array<{ scale: number }>; opacity: number } {
 45→  return useAnimatedStyle(() => {
 46→    const w = Math.max(sign * translateX.value - BUTTON_GAP, 0);
 47→    if (w <= SCALE_MIN_WIDTH) {
 48→      return { transform: [{ scale: 0 }], opacity: 0 };
 49→    }
 50→    if (w < BUTTON_SCALE_THRESHOLD) {
 51→      const s =
 52→        (w - SCALE_MIN_WIDTH) / (BUTTON_SCALE_THRESHOLD - SCALE_MIN_WIDTH);
 53→      return { transform: [{ scale: s }], opacity: s };
 54→    }
 55→    return { transform: [{ scale: 1 }], opacity: 1 };
 56→  });
 57→}
