 59→const SWIPE_THRESHOLD = 60;
 60→const ACTION_BUTTON_WIDTH = 80;
 61→const BUTTON_GAP = 12;
 62→const BUTTON_CONTENT_WIDTH = ACTION_BUTTON_WIDTH - BUTTON_GAP;
 63→const BUTTON_SCALE_THRESHOLD = BUTTON_CONTENT_WIDTH;
 64→const SCALE_MIN_WIDTH = 10;
 65→
 66→function SwipeableBookRow({
