 81→  onDelete: (sourceId: SourceId) => void;
 82→  onStartEdit: (sourceId: SourceId) => void;
 83→  onSetLanguage: (sourceId: SourceId) => void;
 84→  onConfirmEdit: () => void;
 85→  onCancelEdit: () => void;
 86→  editText: string;
 87→  onEditTextChange: (text: string) => void;
 88→}): JSX.Element {
 89→  const { t } = useTranslation();
 90→  const theme = useTheme();
 91→  const colors = getColors(theme);
 92→  const isDark = theme === "dark";
 93→  const textColor = isDark ? "#FFFFFF" : "#000000";
 94→  const translateX = useSharedValue(0);
 95→  const startX = useSharedValue(0);
 96→  const isEditing = editingSourceId === source.id;
 97→  const isEditingShared = useSharedValue(isEditing);
 98→
 99→  isEditingShared.value = isEditing;
100→
101→  useEffect(() => {
102→    translateX.value = withSpring(isEditing ? ACTION_BUTTON_WIDTH : 0);
103→  }, [isEditing, translateX]);
104→
105→  const triggerDelete = useCallback(() => {
106→    translateX.value = withSpring(0);
107→    onDelete(source.id);
108→  }, [source.id, onDelete, translateX]);
109→
110→  const handleEditPress = useCallback(() => {
111→    if (isEditing) {
