135→          translateX.value = withSpring(ACTION_BUTTON_WIDTH);
136→        }
137→      } else {
138→        if (translateX.value < -SWIPE_THRESHOLD) {
139→          translateX.value = withSpring(-ACTION_BUTTON_WIDTH);
140→        } else if (translateX.value > SWIPE_THRESHOLD) {
141→          translateX.value = withSpring(ACTION_BUTTON_WIDTH);
142→        } else {
143→          translateX.value = withSpring(0);
144→        }
145→      }
146→    });
147→
