165→      [0, 1],
166→      isDark
167→        ? ["rgba(44,43,45,0)", "#2c2b2d"]
168→        : ["rgba(128,128,128,0)", "rgba(128,128,128,0.12)"]
169→    );
170→    return {
171→      backgroundColor: bgColor,
172→      borderRadius: interpolate(progress, [0, 1], [0, 21]),
173→    };
174→  });
175→
176→  const editButtonWidthStyle = useAnimatedStyle(() => ({
177→    width: translateX.value > BUTTON_GAP ? translateX.value - BUTTON_GAP : 0,
178→    opacity: translateX.value > BUTTON_GAP ? 1 : 0,
179→  }));
180→
181→  const deleteButtonWidthStyle = useAnimatedStyle(() => ({
182→    width: -translateX.value > BUTTON_GAP ? -translateX.value - BUTTON_GAP : 0,
183→    opacity: -translateX.value > BUTTON_GAP ? 1 : 0,
184→  }));
185→
