282→              </Text>
283→              <Text
284→                style={[styles.recipeCount, { color: colors.textSecondary }]}
285→              >
286→                {t("manageBooks.recipeCount", { count: recipeCount })}
287→                {" · "}
288→                <Text onPress={() => onSetLanguage(source.id)}>
289→                  {source.language.toUpperCase()}
290→                </Text>
