378→                  (r) => r.metadata.source === sourceId
379→                );
380→                await deleteRecipes(recipesToDelete.map((recipe) => recipe.id));
381→                LayoutAnimation.configureNext(
382→                  LayoutAnimation.Presets.easeInEaseOut
383→                );
384→                await deleteSource(sourceId);
385→              } finally {
