 60→const ACTION_BUTTON_WIDTH = 80;
 61→const LEFT_REVEAL_WIDTH = ACTION_BUTTON_WIDTH * 2;
 62→const BUTTON_GAP = 12;
 63→const BUTTON_CONTENT_WIDTH = ACTION_BUTTON_WIDTH - BUTTON_GAP;
 64→const BUTTON_SCALE_THRESHOLD = BUTTON_CONTENT_WIDTH;
 65→const SCALE_MIN_WIDTH = 10;
 66→
 67→function SwipeableBookRow({
 68→  source,
 69→  recipeCount,
 70→  editingSourceId,
 71→  onDelete,
 72→  onStartEdit,
 73→  onSetLanguage,
 74→  onConfirmEdit,
 75→  onCancelEdit,
 76→  editText,
 77→  onEditTextChange,
 78→}: {
 79→  source: Source;
 80→  recipeCount: number;
 81→  editingSourceId: SourceId | null;
 82→  onDelete: (sourceId: SourceId) => void;
 83→  onStartEdit: (sourceId: SourceId) => void;
 84→  onSetLanguage: (sourceId: SourceId) => void;
 85→  onConfirmEdit: () => void;
 86→  onCancelEdit: () => void;
 87→  editText: string;
 88→  onEditTextChange: (text: string) => void;
 89→}): JSX.Element {
 90→  const { t } = useTranslation();
 91→  const theme = useTheme();
 92→  const colors = getColors(theme);
 93→  const isDark = theme === "dark";
 94→  const textColor = isDark ? "#FFFFFF" : "#000000";
 95→  const translateX = useSharedValue(0);
 96→  const startX = useSharedValue(0);
 97→  const isEditing = editingSourceId === source.id;
 98→  const isEditingShared = useSharedValue(isEditing);
 99→
100→  isEditingShared.value = isEditing;
101→
102→  useEffect(() => {
103→    translateX.value = withSpring(isEditing ? LEFT_REVEAL_WIDTH : 0);
104→  }, [isEditing, translateX]);
105→
106→  const triggerDelete = useCallback(() => {
107→    translateX.value = withSpring(0);
108→    onDelete(source.id);
109→  }, [source.id, onDelete, translateX]);
110→
111→  const handleEditPress = useCallback(() => {
112→    if (isEditing) {
113→      onConfirmEdit();
114→    } else {
115→      onStartEdit(source.id);
116→    }
117→  }, [isEditing, onConfirmEdit, onStartEdit, source.id]);
118→
119→  const pan = Gesture.Pan()
120→    .activeOffsetX([-10, 10])
121→    .failOffsetY([-10, 10])
122→    .onStart(() => {
123→      startX.value = translateX.value;
124→    })
125→    .onUpdate((event) => {
126→      const raw = startX.value + event.translationX;
127→      const leftLimit = LEFT_REVEAL_WIDTH * 1.5;
128→      const rightLimit = ACTION_BUTTON_WIDTH * 1.5;
129→      translateX.value = Math.max(-rightLimit, Math.min(leftLimit, raw));
130→    })
131→    .onEnd(() => {
132→      if (isEditingShared.value) {
133→        if (translateX.value < SWIPE_THRESHOLD / 2) {
134→          translateX.value = withSpring(0);
135→          runOnJS(onCancelEdit)();
136→        } else {
137→          translateX.value = withSpring(LEFT_REVEAL_WIDTH);
138→        }
