492→private struct BackspaceAwareTextField: UIViewRepresentable {
493→  @Binding var text: String
494→  var placeholder: String
495→  var returnKeyType: UIReturnKeyType
496→  @Binding var isFocused: Bool
497→  var blurOnSubmit: Bool
498→  var onFocus: () -> Void
499→  var onBlur: () -> Void
500→  var onSubmit: () -> Void
501→  var onEmptyBackspace: () -> Void
502→
503→  func makeUIView(context: Context) -> DeletingAwareUITextField {
504→    let textField = DeletingAwareUITextField(frame: .zero)
505→    textField.borderStyle = .none
506→    textField.font = UIFont.systemFont(ofSize: 16)
507→    textField.textColor = .label
508→    textField.backgroundColor = .clear
509→    textField.returnKeyType = returnKeyType
510→    textField.placeholder = placeholder
511→    textField.attributedPlaceholder = NSAttributedString(
512→      string: placeholder,
513→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
514→    )
515→    textField.delegate = context.coordinator
516→    textField.onEmptyBackspace = onEmptyBackspace
517→    textField.addTarget(
518→      context.coordinator,
519→      action: #selector(Coordinator.handleEditingChanged(_:)),
520→      for: .editingChanged
521→    )
522→    return textField
523→  }
524→
525→  func updateUIView(_ uiView: DeletingAwareUITextField, context: Context) {
526→    if uiView.text != text {
527→      uiView.text = text
528→    }
529→
530→    uiView.returnKeyType = returnKeyType
531→    uiView.placeholder = placeholder
532→    uiView.attributedPlaceholder = NSAttributedString(
533→      string: placeholder,
534→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
535→    )
536→    uiView.onEmptyBackspace = onEmptyBackspace
537→
538→    if isFocused && !uiView.isFirstResponder {
539→      uiView.becomeFirstResponder()
540→    } else if !isFocused && uiView.isFirstResponder {
541→      uiView.resignFirstResponder()
542→    }
543→  }
544→
545→  func makeCoordinator() -> Coordinator {
546→    Coordinator(
547→      text: $text,
548→      isFocused: $isFocused,
549→      blurOnSubmit: blurOnSubmit,
550→      onFocus: onFocus,
551→      onBlur: onBlur,
552→      onSubmit: onSubmit
553→    )
554→  }
555→
556→  final class Coordinator: NSObject, UITextFieldDelegate {
557→    private var text: Binding<String>
558→    private var isFocused: Binding<Bool>
559→    private let blurOnSubmit: Bool
560→    private let onFocus: () -> Void
561→    private let onBlur: () -> Void
562→    private let onSubmit: () -> Void
563→
564→    init(
565→      text: Binding<String>,
566→      isFocused: Binding<Bool>,
567→      blurOnSubmit: Bool,
568→      onFocus: @escaping () -> Void,
569→      onBlur: @escaping () -> Void,
570→      onSubmit: @escaping () -> Void
571→    ) {
572→      self.text = text
573→      self.isFocused = isFocused
574→      self.blurOnSubmit = blurOnSubmit
575→      self.onFocus = onFocus
576→      self.onBlur = onBlur
577→      self.onSubmit = onSubmit
578→    }
579→
580→    @objc
581→    func handleEditingChanged(_ textField: UITextField) {
582→      text.wrappedValue = textField.text ?? ""
583→    }
584→
585→    func textFieldDidBeginEditing(_ textField: UITextField) {
586→      if !isFocused.wrappedValue {
587→        isFocused.wrappedValue = true
588→      }
589→      onFocus()
590→    }
591→
592→    func textFieldDidEndEditing(_ textField: UITextField) {
593→      if isFocused.wrappedValue {
594→        isFocused.wrappedValue = false
595→      }
596→      onBlur()
