 1→import { preferencesRepository } from "@/lib/repositories/preferences";
 2→import type { AppLanguage } from "@/lib/types/language";
 3→import i18n from "@/platform/i18n/config";
 4→import {
 5→  createContext,
 6→  use,
 7→  useCallback,
 8→  useContext,
 9→  useMemo,
10→  useState,
11→  type JSX,
12→  type ReactNode,
13→} from "react";
14→
15→type PreferencesContextValue = {
16→  uiLanguage: AppLanguage;
17→  ocrLanguage: AppLanguage;
18→  setUiLanguage: (lang: AppLanguage) => Promise<void>;
19→  setOcrLanguage: (lang: AppLanguage) => Promise<void>;
20→};
21→
22→const PreferencesContext = createContext<PreferencesContextValue | null>(null);
23→
24→let preferencesPromise: Promise<{
25→  uiLanguage: AppLanguage;
26→  ocrLanguage: AppLanguage;
27→}> | null = null;
28→
29→function getPreferencesPromise(): Promise<{
30→  uiLanguage: AppLanguage;
31→  ocrLanguage: AppLanguage;
32→}> {
33→  if (!preferencesPromise) {
34→    preferencesPromise = Promise.all([
35→      preferencesRepository.getUiLanguage(),
36→      preferencesRepository.getOcrLanguage(),
37→    ]).then(([uiLanguage, ocrLanguage]) => {
38→      i18n.changeLanguage(uiLanguage);
39→      return { uiLanguage, ocrLanguage };
40→    });
41→  }
42→  return preferencesPromise;
43→}
44→
45→export function PreferencesProvider({
46→  children,
47→}: {
48→  children: ReactNode;
49→}): JSX.Element {
50→  const initial = use(getPreferencesPromise());
51→  const [uiLanguage, setUiLanguageState] = useState<AppLanguage>(
52→    initial.uiLanguage
53→  );
54→  const [ocrLanguage, setOcrLanguageState] = useState<AppLanguage>(
55→    initial.ocrLanguage
56→  );
57→
58→  const setUiLanguage = useCallback(
59→    async (lang: AppLanguage): Promise<void> => {
60→      await preferencesRepository.setUiLanguage(lang);
61→      await i18n.changeLanguage(lang);
62→      setUiLanguageState(lang);
63→    },
